1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	};
10	
11	const basePremium = (item: { type: string }): number =>
12	  BASE_PREMIUMS[item.type] ?? 0;
13	
14	interface Customer {
15	  yearsWithMHPCO: number;
16	}
17	
18	interface QuoteResult {
19	  premium: number;
20	}
21	
22	const quotePremium = (items: Array<{ type: string }>): number =>
23	  items.reduce((sum, item) => sum + basePremium(item), 0) + PROCESSING_FEE;
24	
25	export const processSteps = (customer: Customer, steps: Array<{ op: string; items: Array<{ type: string }> }>): Array<QuoteResult> =>
26	  steps.map((step) => ({
27	    premium: quotePremium(step.items),
28	  }));
